export type KolType = "whale" | "dumper" | "diamond" | "degen" | "rugger";

export function getKolType(kol: KOL): KolType {
  if (kol.pnlSol < -100) return "rugger";
  const ratio = kol.sells / Math.max(kol.buys, 1);
  if (ratio > 2) return "dumper";
  if (ratio < 0.3 && kol.buys > 0) return "diamond";
  if (kol.trades > 50) return "degen";
  return "whale";
}
